const formContainer = document.querySelector('.form-container');
const reportForm = document.getElementById('report-form');
const latInput = document.getElementById('latitude');
const lngInput = document.getElementById('longitude');
const closeFormButton = document.getElementById('close-form-btn');
const categorySelect = document.getElementById('category');
const otherCategoryWrapper = document.getElementById('other-category-wrapper');
const otherCategoryInput = document.getElementById('other-category-input');
const instructionBox = document.getElementById('instruction-box');
const photoInput = document.getElementById('photo');

// --- MAP INITIALIZATION ---
const map = L.map('map').setView([-2.5489, 118.0149], 5); // Center on Indonesia, zoomed out
L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    minZoom: 5, // Set a minimum zoom level
}).addTo(map);

// --- MAP BOUNDARIES ---
// Define the corners of a box around Indonesia
const corner1 = L.latLng(6.0, 95.0); // Top-left corner
const corner2 = L.latLng(-11.0, 141.0); // Bottom-right corner
const bounds = L.latLngBounds(corner1, corner2);
// Set the maximum boundaries for the map
map.setMaxBounds(bounds);
map.on('drag', function() {
    map.panInsideBounds(bounds, { animate: false });
});

// --- GEOSEARCH PLUGIN (FIXED) ---
// Use the 'leaflet-geosearch' library which is loaded in index.html
const provider = new GeoSearch.OpenStreetMapProvider();
const searchControl = new GeoSearch.GeoSearchControl({
  provider: provider,
  style: 'bar',
  showMarker: true, // Let's show a marker on search result
  marker: {
    icon: new L.Icon.Default(),
    draggable: false,
  },
  autoClose: true,
  keepResult: true,
  position: 'topright',
});
map.addControl(searchControl);


// --- GLOBAL VARIABLE ---
let tempMarker = null;

// --- EVENT LISTENERS ---
map.on('click', function(e) {
    if (instructionBox) {
        instructionBox.style.display = 'none';
    }
    if (tempMarker) {
        map.removeLayer(tempMarker);
    }
    const latlng = e.latlng;
    tempMarker = L.marker(latlng).addTo(map);
    latInput.value = latlng.lat;
    lngInput.value = latlng.lng;
    formContainer.style.display = 'block';
});

reportForm.addEventListener('submit', function(e) {
    e.preventDefault();
    const lat = latInput.value;
    const lng = lngInput.value;
    const description = document.getElementById('description').value;

    let categoryText;
    if (categorySelect.value === 'other') {
        categoryText = otherCategoryInput.value;
    } else {
        categoryText = categorySelect.options[categorySelect.selectedIndex].text;
    }

    const photoFile = photoInput.files[0];

    const createMarker = (photoUrl) => {
        let popupContent = `<b>${categoryText}</b><br>${description}`;
        if (photoUrl) {
            popupContent += `<br><img src="${photoUrl}" alt="Foto Laporan" width="150">`;
        }
        L.marker([lat, lng]).addTo(map).bindPopup(popupContent).openPopup();

        formContainer.style.display = 'none';
        map.removeLayer(tempMarker);
        reportForm.reset();
        otherCategoryWrapper.style.display = 'none';
    };

    if (photoFile) {
        const reader = new FileReader();
        reader.onload = function(event) {
            createMarker(event.target.result);
        };
        reader.readAsDataURL(photoFile);
    } else {
        createMarker(null);
    }
});

closeFormButton.addEventListener('click', function() {
    formContainer.style.display = 'none';
    if (tempMarker) {
        map.removeLayer(tempMarker);
    }
});

categorySelect.addEventListener('change', function() {
    if (categorySelect.value === 'other') {
        otherCategoryWrapper.style.display = 'block';
        otherCategoryInput.required = true;
    } else {
        otherCategoryWrapper.style.display = 'none';
        otherCategoryInput.required = false;
    }
});

