{
  "name": "Peta Fasilitas Publik",
  "description": "Aplikasi pelaporan fasilitas publik rusak berbasis peta interaktif dengan fitur geolokasi dan unggah foto."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ReportCategory = 'streetlight' | 'pothole' | 'trashcan' | 'playground' | 'other';

export interface Report {
  id: string;
  lat: number;
  lng: number;
  category: ReportCategory;
  categoryLabel: string;
  description: string;
  photoUrl: string | null;
  timestamp: number;
}

export interface NewReportForm {
  lat: number;
  lng: number;
}

import React from 'react';

interface InstructionBoxProps {
  visible: boolean;
}

export const InstructionBox: React.FC<InstructionBoxProps> = ({ visible }) => {
  if (!visible) return null;

  return (
    <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[999] bg-black/70 backdrop-blur-sm text-white px-5 py-2.5 rounded-full text-sm pointer-events-none transition-opacity duration-300">
      Klik di peta untuk membuat laporan
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { ReportCategory } from '../types';
import { X, Upload } from 'lucide-react';

interface ReportFormProps {
  lat: number;
  lng: number;
  onClose: () => void;
  onSubmit: (data: {
    category: ReportCategory;
    categoryLabel: string;
    description: string;
    photoUrl: string | null;
  }) => void;
}

export const ReportForm: React.FC<ReportFormProps> = ({ lat, lng, onClose, onSubmit }) => {
  const [category, setCategory] = useState<ReportCategory>('streetlight');
  const [otherCategory, setOtherCategory] = useState('');
  const [description, setDescription] = useState('');
  const [photoUrl, setPhotoUrl] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setPhotoUrl(event.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let categoryLabel = '';
    switch (category) {
      case 'streetlight': categoryLabel = 'Lampu Jalan'; break;
      case 'pothole': categoryLabel = 'Jalan Berlubang'; break;
      case 'trashcan': categoryLabel = 'Tempat Sampah'; break;
      case 'playground': categoryLabel = 'Alat Taman Bermain'; break;
      case 'other': categoryLabel = otherCategory || 'Lainnya'; break;
    }

    onSubmit({
      category,
      categoryLabel,
      description,
      photoUrl
    });
  };

  return (
    <div className="fixed top-5 right-5 z-[1000] w-full max-w-[320px] p-6 rounded-xl bg-white shadow-2xl animate-fade-in border border-gray-100">
      <button 
        onClick={onClose}
        className="absolute top-3 right-3 p-1 rounded-full hover:bg-gray-100 transition-colors text-gray-400 hover:text-gray-600"
      >
        <X size={20} />
      </button>

      <h2 className="text-xl font-bold mb-5 text-gray-800">Laporkan Fasilitas</h2>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="text-xs text-gray-500 bg-gray-50 p-2 rounded mb-2">
          Lokasi: {lat.toFixed(5)}, {lng.toFixed(5)}
        </div>

        <div>
          <label htmlFor="category" className="block text-sm font-semibold text-gray-700 mb-1">Kategori</label>
          <select 
            id="category" 
            value={category} 
            onChange={(e) => setCategory(e.target.value as ReportCategory)}
            className="w-full p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all bg-white"
          >
            <option value="streetlight">Lampu Jalan</option>
            <option value="pothole">Jalan Berlubang</option>
            <option value="trashcan">Tempat Sampah</option>
            <option value="playground">Alat Taman Bermain</option>
            <option value="other">Lainnya</option>
          </select>
        </div>

        {category === 'other' && (
          <div className="animate-fade-in-down">
            <label htmlFor="other-input" className="block text-sm font-semibold text-gray-700 mb-1">Sebutkan Kategori</label>
            <input 
              type="text" 
              id="other-input"
              value={otherCategory}
              onChange={(e) => setOtherCategory(e.target.value)}
              required
              className="w-full p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="Contoh: Halte Bus Rusak"
            />
          </div>
        )}

        <div>
          <label htmlFor="description" className="block text-sm font-semibold text-gray-700 mb-1">Deskripsi</label>
          <textarea 
            id="description" 
            rows={3} 
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
            className="w-full p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none"
            placeholder="Jelaskan kerusakan..."
          />
        </div>

        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">Foto (Opsional)</label>
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="w-full p-4 border-2 border-dashed border-gray-300 rounded-lg cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-all flex flex-col items-center justify-center text-gray-500"
          >
            {photoUrl ? (
               <img src={photoUrl} alt="Preview" className="h-24 object-cover rounded" />
            ) : (
              <>
                <Upload size={24} className="mb-2" />
                <span className="text-xs">Klik untuk unggah foto</span>
              </>
            )}
            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleFileChange}
              accept="image/*"
              className="hidden"
            />
          </div>
        </div>

        <button 
          type="submit" 
          className="w-full py-3 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-lg font-semibold hover:from-blue-700 hover:to-blue-800 transition-all shadow-md hover:shadow-lg active:scale-[0.98]"
        >
          Kirim Laporan
        </button>
      </form>
    </div>
  );
};

import { useEffect } from 'react';
import { useMap } from 'react-leaflet';
import { GeoSearchControl, OpenStreetMapProvider } from 'leaflet-geosearch';
import L from 'leaflet';

// Define proper types for leaflet-geosearch
interface GeoSearchProps {
  provider: any; // OpenStreetMapProvider
  style?: 'bar' | 'button';
  showMarker?: boolean;
  showPopup?: boolean;
  marker?: object;
  maxMarkers?: number;
  retainZoomLevel?: boolean;
  animateZoom?: boolean;
  autoClose?: boolean;
  searchLabel?: string;
  keepResult?: boolean;
}

export const SearchField = () => {
  const map = useMap();

  useEffect(() => {
    // @ts-ignore - Types for GeoSearchControl are slightly loose in the library
    const provider = new OpenStreetMapProvider();

    // @ts-ignore
    const searchControl = new GeoSearchControl({
      provider: provider,
      style: 'bar',
      showMarker: false, // We handle markers ourselves if needed, or let user click
      showPopup: false,
      autoClose: true,
      retainZoomLevel: false,
      animateZoom: true,
      keepResult: false,
      searchLabel: 'Cari lokasi...',
    });

    map.addControl(searchControl);

    return () => {
      map.removeControl(searchControl);
    };
  }, [map]);

  return null;
};

import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Report, ReportCategory } from './types';
import { InstructionBox } from './components/InstructionBox';
import { ReportForm } from './components/ReportForm';
import { SearchField } from './components/SearchField';

// Fix for default Leaflet icons in React/Webpack environments
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
});
L.Marker.prototype.options.icon = DefaultIcon;

// Custom red icon for the temporary marker
const tempIcon = new L.Icon({
    iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-red.png',
    shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png',
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
    shadowSize: [41, 41]
});

// Component to handle map clicks
const MapEvents = ({ onMapClick }: { onMapClick: (lat: number, lng: number) => void }) => {
  useMapEvents({
    click(e) {
      onMapClick(e.latlng.lat, e.latlng.lng);
    },
  });
  return null;
};

const App: React.FC = () => {
  const [reports, setReports] = useState<Report[]>([]);
  const [tempLocation, setTempLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [instructionVisible, setInstructionVisible] = useState(true);

  // Initial Indonesia Bounds
  const indonesiaCenter: L.LatLngExpression = [-2.5489, 118.0149];
  const bounds = L.latLngBounds(L.latLng(6.0, 95.0), L.latLng(-11.0, 141.0));

  const handleMapClick = (lat: number, lng: number) => {
    setInstructionVisible(false);
    setTempLocation({ lat, lng });
    setIsFormOpen(true);
  };

  const handleCloseForm = () => {
    setIsFormOpen(false);
    setTempLocation(null);
  };

  const handleSubmitReport = (data: {
    category: ReportCategory;
    categoryLabel: string;
    description: string;
    photoUrl: string | null;
  }) => {
    if (!tempLocation) return;

    const newReport: Report = {
      id: Date.now().toString(),
      lat: tempLocation.lat,
      lng: tempLocation.lng,
      ...data,
      timestamp: Date.now(),
    };

    setReports((prev) => [...prev, newReport]);
    setIsFormOpen(false);
    setTempLocation(null);
  };

  return (
    <div className="h-screen w-full relative overflow-hidden bg-gray-100">
      <MapContainer 
        center={indonesiaCenter} 
        zoom={5} 
        minZoom={5}
        maxBounds={bounds}
        maxBoundsViscosity={1.0}
        scrollWheelZoom={true}
        className="h-full w-full z-0"
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        <SearchField />
        <MapEvents onMapClick={handleMapClick} />

        {/* Saved Reports */}
        {reports.map((report) => (
          <Marker key={report.id} position={[report.lat, report.lng]}>
            <Popup className="custom-popup">
              <div className="min-w-[200px]">
                <h3 className="font-bold text-lg text-blue-600 mb-1">{report.categoryLabel}</h3>
                <p className="text-gray-700 text-sm mb-2">{report.description}</p>
                {report.photoUrl && (
                  <img 
                    src={report.photoUrl} 
                    alt="Laporan" 
                    className="w-full h-32 object-cover rounded-md border border-gray-200" 
                  />
                )}
                <div className="text-xs text-gray-400 mt-2 text-right">
                  {new Date(report.timestamp).toLocaleDateString()}
                </div>
              </div>
            </Popup>
          </Marker>
        ))}

        {/* Temporary Marker (during form creation) */}
        {tempLocation && (
          <Marker 
            position={[tempLocation.lat, tempLocation.lng]} 
            icon={tempIcon}
          />
        )}
      </MapContainer>

      <InstructionBox visible={instructionVisible && !isFormOpen} />

      {isFormOpen && tempLocation && (
        <ReportForm 
          lat={tempLocation.lat} 
          lng={tempLocation.lng} 
          onClose={handleCloseForm}
          onSubmit={handleSubmitReport}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Report, ReportCategory } from './types';
import { InstructionBox } from './components/InstructionBox';
import { ReportForm } from './components/ReportForm';
import { SearchField } from './components/SearchField';

// Fix for default Leaflet icons in React/ESM environments without bundlers
// We cannot import images directly (e.g. import icon from './image.png') in this environment
delete (L.Icon.Default.prototype as any)._getIconUrl;

L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

// Custom red icon for the temporary marker
const tempIcon = new L.Icon({
    iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-red.png',
    shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png',
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
    shadowSize: [41, 41]
});

// Component to handle map clicks
const MapEvents = ({ onMapClick }: { onMapClick: (lat: number, lng: number) => void }) => {
  useMapEvents({
    click(e) {
      onMapClick(e.latlng.lat, e.latlng.lng);
    },
  });
  return null;
};

const App: React.FC = () => {
  const [reports, setReports] = useState<Report[]>([]);
  const [tempLocation, setTempLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [instructionVisible, setInstructionVisible] = useState(true);

  // Initial Indonesia Bounds
  const indonesiaCenter: L.LatLngExpression = [-2.5489, 118.0149];
  const bounds = L.latLngBounds(L.latLng(6.0, 95.0), L.latLng(-11.0, 141.0));

  const handleMapClick = (lat: number, lng: number) => {
    setInstructionVisible(false);
    setTempLocation({ lat, lng });
    setIsFormOpen(true);
  };

  const handleCloseForm = () => {
    setIsFormOpen(false);
    setTempLocation(null);
  };

  const handleSubmitReport = (data: {
    category: ReportCategory;
    categoryLabel: string;
    description: string;
    photoUrl: string | null;
  }) => {
    if (!tempLocation) return;

    const newReport: Report = {
      id: Date.now().toString(),
      lat: tempLocation.lat,
      lng: tempLocation.lng,
      ...data,
      timestamp: Date.now(),
    };

    setReports((prev) => [...prev, newReport]);
    setIsFormOpen(false);
    setTempLocation(null);
  };

  return (
    <div className="h-screen w-full relative overflow-hidden bg-gray-100">
      <MapContainer 
        center={indonesiaCenter} 
        zoom={5} 
        minZoom={5}
        maxBounds={bounds}
        maxBoundsViscosity={1.0}
        scrollWheelZoom={true}
        className="h-full w-full z-0"
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        <SearchField />
        <MapEvents onMapClick={handleMapClick} />

        {/* Saved Reports */}
        {reports.map((report) => (
          <Marker key={report.id} position={[report.lat, report.lng]}>
            <Popup className="custom-popup">
              <div className="min-w-[200px]">
                <h3 className="font-bold text-lg text-blue-600 mb-1">{report.categoryLabel}</h3>
                <p className="text-gray-700 text-sm mb-2">{report.description}</p>
                {report.photoUrl && (
                  <img 
                    src={report.photoUrl} 
                    alt="Laporan" 
                    className="w-full h-32 object-cover rounded-md border border-gray-200" 
                  />
                )}
                <div className="text-xs text-gray-400 mt-2 text-right">
                  {new Date(report.timestamp).toLocaleDateString()}
                </div>
              </div>
            </Popup>
          </Marker>
        ))}

        {/* Temporary Marker (during form creation) */}
        {tempLocation && (
          <Marker 
            position={[tempLocation.lat, tempLocation.lng]} 
            icon={tempIcon}
          />
        )}
      </MapContainer>

      <InstructionBox visible={instructionVisible && !isFormOpen} />

      {isFormOpen && tempLocation && (
        <ReportForm 
          lat={tempLocation.lat} 
          lng={tempLocation.lng} 
          onClose={handleCloseForm}
          onSubmit={handleSubmitReport}
        />
      )}
    </div>
  );
};

export default App;

