// Define proper types for leaflet-geosearch
interface GeoSearchProps {
  provider: any; // OpenStreetMapProvider
  style?: 'bar' | 'button';
  showMarker?: boolean;
  showPopup?: boolean;
  marker?: object;
  maxMarkers?: number;
  retainZoomLevel?: boolean;
  animateZoom?: boolean;
  autoClose?: boolean;
  searchLabel?: string;
  keepResult?: boolean;
}

export const SearchField = () => {
  const map = useMap();

  useEffect(() => {
    // @ts-ignore - Types for GeoSearchControl are slightly loose in the library
    const provider = new OpenStreetMapProvider({
      params: {
        'accept-language': 'id', // Render results in Indonesian
        countrycodes: 'id',      // Limit results to Indonesia (ISO 3166-1 alpha-2 code)
      },
    });

    // @ts-ignore
    const searchControl = new GeoSearchControl({
      provider: provider,
      style: 'bar',
      showMarker: false, // We handle markers ourselves if needed, or let user click
      showPopup: false,
      autoClose: true,
      retainZoomLevel: false,
      animateZoom: true,
      keepResult: false,
      searchLabel: 'Cari lokasi di Indonesia...',
    });

    map.addControl(searchControl);

    return () => {
      map.removeControl(searchControl);
    };
  }, [map]);

  return null;
};

