import React, { useState } from 'react';
import { Report, ReportCategory, HazardLevel } from '../types';
import { Search, MapPin, Calendar, Image as ImageIcon, AlertTriangle, Lightbulb, Trash2, Palmtree, HelpCircle, ChevronLeft, AlertCircle, CheckCircle2, Filter } from 'lucide-react';

interface ReportSidebarProps {
  reports: Report[];
  onReportClick: (report: Report) => void;
  onCollapse: () => void;
}

const getCategoryStyles = (category: ReportCategory) => {
  switch (category) {
    case 'pothole':
      return { bg: 'bg-red-50', text: 'text-red-700', border: 'border-red-200', icon: AlertTriangle };
    case 'streetlight':
      return { bg: 'bg-yellow-50', text: 'text-yellow-700', border: 'border-yellow-200', icon: Lightbulb };
    case 'trashcan':
      return { bg: 'bg-green-50', text: 'text-green-700', border: 'border-green-200', icon: Trash2 };
    case 'playground':
      return { bg: 'bg-purple-50', text: 'text-purple-700', border: 'border-purple-200', icon: Palmtree };
    default:
      return { bg: 'bg-gray-50', text: 'text-gray-700', border: 'border-gray-200', icon: HelpCircle };
  }
};

const getHazardInfo = (level: HazardLevel) => {
  switch (level) {
    case 'high':
      return { bg: 'bg-red-100', text: 'text-red-700', label: 'Tinggi', icon: AlertCircle, color: 'red' };
    case 'medium':
      return { bg: 'bg-yellow-100', text: 'text-yellow-700', label: 'Sedang', icon: AlertTriangle, color: 'yellow' };
    case 'low':
      return { bg: 'bg-green-100', text: 'text-green-700', label: 'Rendah', icon: CheckCircle2, color: 'green' };
  }
};

export const ReportSidebar: React.FC<ReportSidebarProps> = ({ reports, onReportClick, onCollapse }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [hazardFilter, setHazardFilter] = useState<HazardLevel | 'all'>('all');

  const filteredReports = reports.filter((report) => {
    const matchesSearch = 
      report.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
      report.categoryLabel.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (report.address || '').toLowerCase().includes(searchQuery.toLowerCase());

    const matchesHazard = hazardFilter === 'all' || report.hazardLevel === hazardFilter;

    return matchesSearch && matchesHazard;
  });

  return (
    <div className="absolute left-0 top-0 h-full w-full md:w-[420px] bg-white shadow-2xl z-[1001] flex flex-col border-r border-gray-200 transform transition-transform duration-300 ease-in-out md:relative md:transform-none">

      {/* Desktop Collapse Button - Vertically Centered */}
      <button 
        onClick={onCollapse}
        className="hidden md:flex absolute -right-3 top-1/2 -translate-y-1/2 z-50 bg-white text-gray-600 hover:text-blue-600 w-8 h-12 rounded-r-lg shadow-md border-y border-r border-gray-200 items-center justify-center transition-all hover:w-10"
        title="Sembunyikan Sidebar"
        style={{ right: '0' }} // Overwrite -right-3 to be inside or stick to edge
      >
        <ChevronLeft size={20} />
      </button>

      {/* Header with Gradient */}
      <div className="p-6 bg-gradient-to-br from-blue-700 to-indigo-800 text-white shadow-lg z-10 relative">
        <h1 className="text-2xl font-bold mb-1 tracking-tight">Lapor Fasilitas</h1>
        <p className="text-blue-100 text-sm mb-4 opacity-90">Pantau dan laporkan kerusakan di kotamu.</p>

        {/* Search Bar */}
        <div className="relative group mb-3">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-blue-600 transition-colors" size={18} />
          <input
            type="text"
            placeholder="Cari lokasi atau masalah..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-200 text-gray-900 placeholder-gray-500 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent transition-all text-sm shadow-sm"
