                  <div className={`inline-flex items-center px-2 py-1 rounded-md text-[10px] font-bold ${hazardInfo.bg} ${hazardInfo.text}`}>
                    <span className="mr-1 opacity-70">Bahaya:</span> {hazardInfo.label}
                  </div>
                </div>

                <h3 className="text-gray-800 font-semibold text-sm mb-2 pl-2 line-clamp-2">
                  {report.description}
                </h3>

                <div className="flex items-center justify-between pl-2 mt-3 pt-3 border-t border-gray-50">
                  <div className="flex items-start max-w-[70%]">
                     <MapPin size={14} className="text-gray-400 mt-0.5 mr-2 flex-shrink-0" />
                     <div className="text-xs text-gray-500 leading-relaxed truncate">
                       {report.address ? (
                         <span className="font-medium text-gray-600">{report.address}</span>
                       ) : (
                         <span>{report.lat.toFixed(5)}, {report.lng.toFixed(5)}</span>
                       )}
                     </div>
                  </div>

                  <span className="text-[10px] font-medium text-gray-400 flex items-center bg-gray-50 px-2 py-1 rounded-md">
                    <Calendar size={10} className="mr-1.5" />
                    {new Date(report.timestamp).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}
                  </span>
                </div>

                {report.photoUrl && (
                  <div className="absolute bottom-4 right-4 text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">
                    <ImageIcon size={18} />
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>

      <div className="p-4 border-t border-gray-200 bg-white text-center">
        <p className="text-xs text-gray-400 font-medium">
          Menampilkan <span className="text-gray-800 font-bold">{filteredReports.length}</span> laporan
        </p>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { ReportCategory, HazardLevel } from '../types';
import { X, Upload, AlertCircle, AlertTriangle, CheckCircle2, Info } from 'lucide-react';

interface ReportFormProps {
  lat: number;
  lng: number;
  onClose: () => void;
  onSubmit: (data: {
    category: ReportCategory;
    categoryLabel: string;
    description: string;
    photoUrl: string | null;
    hazardLevel: HazardLevel;
  }) => void;
}

export const ReportForm: React.FC<ReportFormProps> = ({ lat, lng, onClose, onSubmit }) => {
  const [category, setCategory] = useState<ReportCategory>('streetlight');
  const [otherCategory, setOtherCategory] = useState('');
  const [description, setDescription] = useState('');
  const [hazardLevel, setHazardLevel] = useState<HazardLevel>('medium');
  const [photoUrl, setPhotoUrl] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setPhotoUrl(event.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let categoryLabel = '';
    switch (category) {
      case 'streetlight': categoryLabel = 'Lampu Jalan'; break;
      case 'pothole': categoryLabel = 'Jalan Berlubang'; break;
      case 'trashcan': categoryLabel = 'Tempat Sampah'; break;
      case 'playground': categoryLabel = 'Alat Taman Bermain'; break;
      case 'other': categoryLabel = otherCategory || 'Lainnya'; break;
    }

    onSubmit({
      category,
      categoryLabel,
      description,
      photoUrl,
      hazardLevel
    });
  };

  return (
    <div className="fixed top-5 right-5 z-[1000] w-full max-w-[320px] p-6 rounded-xl bg-white shadow-2xl animate-fade-in border border-gray-100 max-h-[90vh] overflow-y-auto">
      <button 
        onClick={onClose}
        className="absolute top-3 right-3 p-1 rounded-full hover:bg-gray-100 transition-colors text-gray-400 hover:text-gray-600"
      >
        <X size={20} />
      </button>

      <h2 className="text-xl font-bold mb-5 text-gray-800">Laporkan Fasilitas</h2>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="text-xs text-gray-500 bg-gray-50 p-2 rounded mb-2">
          Lokasi: {lat.toFixed(5)}, {lng.toFixed(5)}
        </div>

        {/* Category Selection */}
        <div>
          <label htmlFor="category" className="block text-sm font-semibold text-gray-700 mb-1">Kategori</label>
          <select 
            id="category" 
            value={category} 
            onChange={(e) => setCategory(e.target.value as ReportCategory)}
            className="w-full p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all bg-white text-gray-900"
          >
            <option value="streetlight">Lampu Jalan</option>
            <option value="pothole">Jalan Berlubang</option>
            <option value="trashcan">Tempat Sampah</option>
            <option value="playground">Alat Taman Bermain</option>
            <option value="other">Lainnya</option>
          </select>
        </div>

        {category === 'other' && (
          <div className="animate-fade-in-down">
            <label htmlFor="other-input" className="block text-sm font-semibold text-gray-700 mb-1">Sebutkan Kategori</label>
            <input 
              type="text" 
              id="other-input"
              value={otherCategory}
              onChange={(e) => setOtherCategory(e.target.value)}
              required
              className="w-full p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-gray-900"
              placeholder="Contoh: Halte Bus Rusak"
            />
          </div>
        )}

        {/* Hazard Level Selection */}
        <div>
          <div className="flex items-center mb-2">
            <label className="block text-sm font-semibold text-gray-700">Tingkat Bahaya</label>

            {/* Tooltip Info Icon */}
            <div className="relative group ml-1.5">
              <Info size={16} className="text-gray-400 hover:text-blue-500 cursor-help transition-colors" />

              <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-64 bg-gray-800/95 backdrop-blur text-white text-xs rounded-lg p-3 shadow-xl opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50 pointer-events-none transform translate-y-2 group-hover:translate-y-0">
                <ul className="space-y-2">
                  <li className="flex items-start">
                    <span className="w-2 h-2 rounded-full bg-red-500 mt-1 mr-2 flex-shrink-0 shadow-[0_0_8px_rgba(239,68,68,0.6)]"></span>
                    <span><strong className="text-red-300 block mb-0.5">Tinggi (Urgent)</strong>Bahaya keselamatan atau kerusakan parah. Butuh penanganan segera.</span>
                  </li>
                  <li className="flex items-start">
                    <span className="w-2 h-2 rounded-full bg-yellow-400 mt-1 mr-2 flex-shrink-0 shadow-[0_0_8px_rgba(250,204,21,0.6)]"></span>
                    <span><strong className="text-yellow-300 block mb-0.5">Sedang</strong>Fungsi terganggu. Kerusakan kecil tapi penting, atau kerusakan sedang tidak darurat.</span>
                  </li>
                  <li className="flex items-start">
                    <span className="w-2 h-2 rounded-full bg-green-500 mt-1 mr-2 flex-shrink-0 shadow-[0_0_8px_rgba(34,197,94,0.6)]"></span>
                    <span><strong className="text-green-300 block mb-0.5">Rendah</strong>Kerusakan ringan atau kosmetik. Tidak mengganggu fungsi utama.</span>
                  </li>
                </ul>
                <div className="absolute top-full left-1/2 -translate-x-1/2 -mt-1 border-4 border-transparent border-t-gray-800/95"></div>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-2">
            <button
              type="button"
              onClick={() => setHazardLevel('low')}
              className={`p-2 rounded-lg border flex flex-col items-center justify-center transition-all ${
                hazardLevel === 'low' 
                  ? 'bg-green-50 border-green-500 text-green-700 ring-1 ring-green-500' 
                  : 'border-gray-200 text-gray-500 hover:bg-gray-50'
              }`}
            >
              <CheckCircle2 size={20} className={hazardLevel === 'low' ? 'mb-1 text-green-600' : 'mb-1 text-gray-400'} />
              <span className="text-xs font-medium">Rendah</span>
            </button>

            <button
              type="button"
              onClick={() => setHazardLevel('medium')}
              className={`p-2 rounded-lg border flex flex-col items-center justify-center transition-all ${
                hazardLevel === 'medium' 
                  ? 'bg-yellow-50 border-yellow-500 text-yellow-700 ring-1 ring-yellow-500' 
                  : 'border-gray-200 text-gray-500 hover:bg-gray-50'
              }`}
            >
              <AlertTriangle size={20} className={hazardLevel === 'medium' ? 'mb-1 text-yellow-600' : 'mb-1 text-gray-400'} />
              <span className="text-xs font-medium">Sedang</span>
            </button>

            <button
              type="button"
              onClick={() => setHazardLevel('high')}
              className={`p-2 rounded-lg border flex flex-col items-center justify-center transition-all ${
                hazardLevel === 'high' 
                  ? 'bg-red-50 border-red-500 text-red-700 ring-1 ring-red-500' 
                  : 'border-gray-200 text-gray-500 hover:bg-gray-50'
              }`}
            >
              <AlertCircle size={20} className={hazardLevel === 'high' ? 'mb-1 text-red-600' : 'mb-1 text-gray-400'} />
              <span className="text-xs font-medium">Tinggi</span>
            </button>
          </div>
        </div>

        {/* Description */}
        <div>
          <label htmlFor="description" className="block text-sm font-semibold text-gray-700 mb-1">Deskripsi Masalah</label>
          <textarea 
            id="description" 
            rows={3}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
            className="w-full p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none bg-white text-gray-900 placeholder-gray-400"
            placeholder="Jelaskan kerusakan yang terjadi..."
          />
        </div>

        {/* Photo Upload */}
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">Foto (Opsional)</label>
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="border-2 border-dashed border-gray-300 rounded-lg p-4 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-colors group"
          >
            {photoUrl ? (
              <div className="relative">
                <img src={photoUrl} alt="Preview" className="w-full h-32 object-cover rounded-md" />
                <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity rounded-md">
                   <span className="text-white text-xs font-medium">Ganti Foto</span>
                </div>
              </div>
            ) : (
              <div className="flex flex-col items-center text-gray-500">
                <Upload size={24} className="mb-2 group-hover:text-blue-500 transition-colors" />
                <span className="text-xs">Klik untuk upload foto</span>
              </div>
            )}
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            className="hidden" 
          />
        </div>

        <button 
          type="submit" 
          className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg shadow-lg hover:shadow-xl transition-all transform active:scale-95 flex items-center justify-center"
        >
          Kirim Laporan
        </button>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { Report, ReportCategory, HazardLevel } from '../types';
import { Search, MapPin, Calendar, Image as ImageIcon, AlertTriangle, Lightbulb, Trash2, Palmtree, HelpCircle, ChevronLeft, AlertCircle, CheckCircle2, Filter, Info } from 'lucide-react';

interface ReportSidebarProps {
  reports: Report[];
  onReportClick: (report: Report) => void;
  onCollapse: () => void;
}

const getCategoryStyles = (category: ReportCategory) => {
  switch (category) {
    case 'pothole':
      return { bg: 'bg-red-50', text: 'text-red-700', border: 'border-red-200', icon: AlertTriangle };
    case 'streetlight':
      return { bg: 'bg-yellow-50', text: 'text-yellow-700', border: 'border-yellow-200', icon: Lightbulb };
    case 'trashcan':
      return { bg: 'bg-green-50', text: 'text-green-700', border: 'border-green-200', icon: Trash2 };
    case 'playground':
      return { bg: 'bg-purple-50', text: 'text-purple-700', border: 'border-purple-200', icon: Palmtree };
    default:
      return { bg: 'bg-gray-50', text: 'text-gray-700', border: 'border-gray-200', icon: HelpCircle };
  }
};

const getHazardInfo = (level: HazardLevel) => {
  switch (level) {
    case 'high':
      return { bg: 'bg-red-100', text: 'text-red-700', label: 'Tinggi', icon: AlertCircle, color: 'red' };
    case 'medium':
      return { bg: 'bg-yellow-100', text: 'text-yellow-700', label: 'Sedang', icon: AlertTriangle, color: 'yellow' };
    case 'low':
      return { bg: 'bg-green-100', text: 'text-green-700', label: 'Rendah', icon: CheckCircle2, color: 'green' };
  }
};

export const ReportSidebar: React.FC<ReportSidebarProps> = ({ reports, onReportClick, onCollapse }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [hazardFilter, setHazardFilter] = useState<HazardLevel | 'all'>('all');

  const filteredReports = reports.filter((report) => {
    const matchesSearch = 
      report.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
      report.categoryLabel.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (report.address || '').toLowerCase().includes(searchQuery.toLowerCase());

    const matchesHazard = hazardFilter === 'all' || report.hazardLevel === hazardFilter;

    return matchesSearch && matchesHazard;
  });

  return (
    <div className="absolute left-0 top-0 h-full w-full md:w-[420px] bg-white shadow-2xl z-[1001] flex flex-col border-r border-gray-200 transform transition-transform duration-300 ease-in-out md:relative md:transform-none">

      {/* Desktop Collapse Button - Vertically Centered */}
      <button 
        onClick={onCollapse}
        className="hidden md:flex absolute -right-3 top-1/2 -translate-y-1/2 z-50 bg-white text-gray-600 hover:text-blue-600 w-8 h-12 rounded-r-lg shadow-md border-y border-r border-gray-200 items-center justify-center transition-all hover:w-10"
        title="Sembunyikan Sidebar"
        style={{ right: '0' }} // Overwrite -right-3 to be inside or stick to edge
      >
        <ChevronLeft size={20} />
      </button>

      {/* Header with Gradient */}
      <div className="p-6 bg-gradient-to-br from-blue-700 to-indigo-800 text-white shadow-lg z-10 relative">
        <h1 className="text-2xl font-bold mb-1 tracking-tight">Lapor Fasilitas</h1>
        <p className="text-blue-100 text-sm mb-4 opacity-90">Pantau dan laporkan kerusakan di kotamu.</p>

        {/* Search Bar */}
        <div className="relative group mb-3">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-blue-600 transition-colors" size={18} />
          <input
            type="text"
            placeholder="Cari lokasi atau masalah..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-200 text-gray-900 placeholder-gray-500 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent transition-all text-sm shadow-sm"
          />
        </div>

        {/* Hazard Level Filters */}
        <div className="flex items-center gap-2 mb-1.5">
           <div className="text-[11px] font-bold text-blue-100 opacity-90 uppercase tracking-widest flex items-center">
             Filter Tingkat Bahaya
           </div>

           {/* Tooltip Info Icon */}
           <div className="relative group">
              <Info size={14} className="text-blue-200 hover:text-white cursor-help transition-colors" />

              <div className="absolute top-full left-0 mt-2 w-60 bg-gray-900/95 backdrop-blur text-white text-xs rounded-lg p-3 shadow-xl opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-[2000] pointer-events-none origin-top-left">
                <ul className="space-y-2 text-left normal-case tracking-normal">
                  <li className="flex items-start">
                    <span className="w-2 h-2 rounded-full bg-red-500 mt-1 mr-2 flex-shrink-0"></span>
                    <span><strong className="text-red-300">Tinggi:</strong> Bahaya keselamatan/darurat.</span>
                  </li>
                  <li className="flex items-start">
                    <span className="w-2 h-2 rounded-full bg-yellow-400 mt-1 mr-2 flex-shrink-0"></span>
                    <span><strong className="text-yellow-300">Sedang:</strong> Fungsi terganggu, tidak darurat.</span>
                  </li>
                  <li className="flex items-start">
                    <span className="w-2 h-2 rounded-full bg-green-500 mt-1 mr-2 flex-shrink-0"></span>
                    <span><strong className="text-green-300">Rendah:</strong> Kosmetik/ringan.</span>
                  </li>
                </ul>
              </div>
           </div>
        </div>

        <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
          <button
            onClick={() => setHazardFilter('all')}
            className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all border whitespace-nowrap flex items-center ${
              hazardFilter === 'all' 
                ? 'bg-white text-blue-700 border-white shadow-md' 
                : 'bg-blue-800/50 text-blue-100 border-transparent hover:bg-blue-700'
            }`}
          >
            <Filter size={12} className="mr-1.5" />
            Semua
          </button>

          <button
            onClick={() => setHazardFilter('high')}
            className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all border whitespace-nowrap flex items-center ${
              hazardFilter === 'high' 
                ? 'bg-red-500 text-white border-red-400 shadow-md' 
                : 'bg-blue-800/50 text-blue-100 border-transparent hover:bg-red-900/50'
            }`}
          >
            <AlertCircle size={12} className="mr-1.5" />
            Bahaya Tinggi
          </button>

          <button
            onClick={() => setHazardFilter('medium')}
            className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all border whitespace-nowrap flex items-center ${
              hazardFilter === 'medium' 
                ? 'bg-yellow-400 text-yellow-900 border-yellow-300 shadow-md' 
                : 'bg-blue-800/50 text-blue-100 border-transparent hover:bg-yellow-900/50'
            }`}
          >
            <AlertTriangle size={12} className="mr-1.5" />
            Sedang
          </button>

           <button
            onClick={() => setHazardFilter('low')}
            className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all border whitespace-nowrap flex items-center ${
              hazardFilter === 'low' 
                ? 'bg-green-500 text-white border-green-400 shadow-md' 
                : 'bg-blue-800/50 text-blue-100 border-transparent hover:bg-green-900/50'
            }`}
          >
            <CheckCircle2 size={12} className="mr-1.5" />
            Rendah
          </button>
        </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto bg-gray-50 p-4 space-y-4">
        {filteredReports.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-gray-400 animate-fade-in">
            <div className="bg-gray-100 p-4 rounded-full mb-3">
              <Search size={32} className="opacity-50" />
            </div>
            <p className="font-medium">Tidak ada laporan ditemukan</p>
            <p className="text-xs mt-1">Coba ubah filter atau kata kunci</p>
          </div>
        ) : (
          filteredReports.map((report) => {
            const styles = getCategoryStyles(report.category);
            const hazardInfo = getHazardInfo(report.hazardLevel);
            const Icon = styles.icon;

            return (
              <div
                key={report.id}
                onClick={() => onReportClick(report)}
                className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 hover:shadow-lg hover:border-blue-300 hover:-translate-y-1 cursor-pointer transition-all duration-300 group relative overflow-hidden"
              >
                {/* Decorative side bar based on Hazard Level if filtered, or Category default */}
                <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${hazardFilter !== 'all' ? hazardInfo.bg.replace('bg-', 'bg-') : styles.bg.replace('bg-', 'bg-gradient-to-b from-').replace('-50', '-400')} to-transparent`}></div>

                <div className="flex justify-between items-start mb-3 pl-2">
                  <div className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold ${styles.bg} ${styles.text} border ${styles.border}`}>
                    <Icon size={12} className="mr-1.5" />
                    {report.categoryLabel}
                  </div>

                  <div className={`inline-flex items-center px-2 py-1 rounded-md text-[10px] font-bold ${hazardInfo.bg} ${hazardInfo.text}`}>
                    <span className="mr-1 opacity-70">Bahaya:</span> {hazardInfo.label}
                  </div>
                </div>

                <h3 className="text-gray-800 font-semibold text-sm mb-2 pl-2 line-clamp-2">
                  {report.description}
                </h3>

                <div className="flex items-center justify-between pl-2 mt-3 pt-3 border-t border-gray-50">
                  <div className="flex items-start max-w-[70%]">
                     <MapPin size={14} className="text-gray-400 mt-0.5 mr-2 flex-shrink-0" />
                     <div className="text-xs text-gray-500 leading-relaxed truncate">
                       {report.address ? (
                         <span className="font-medium text-gray-600">{report.address}</span>
                       ) : (
                         <span>{report.lat.toFixed(5)}, {report.lng.toFixed(5)}</span>
                       )}
                     </div>
                  </div>

                  <span className="text-[10px] font-medium text-gray-400 flex items-center bg-gray-50 px-2 py-1 rounded-md">
                    <Calendar size={10} className="mr-1.5" />
                    {new Date(report.timestamp).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}
                  </span>
                </div>

                {report.photoUrl && (
                  <div className="absolute bottom-4 right-4 text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">
                    <ImageIcon size={18} />
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>

      <div className="p-4 border-t border-gray-200 bg-white text-center">
        <p className="text-xs text-gray-400 font-medium">
          Menampilkan <span className="text-gray-800 font-bold">{filteredReports.length}</span> laporan
        </p>
      </div>
    </div>
  );
};

